        var r1 = await client.GetCommentsForPostAsync(5);
        Assert.Single(r1);
        Assert.Equal(1, handler.GetCallCount("/posts/5/comments"));

        var r2 = await client.GetCommentsForPostAsync(5);
        Assert.Single(r2);
        Assert.Equal(1, handler.GetCallCount("/posts/5/comments"));
    }

    // --- Error Handling ---

    // RED: Should throw a meaningful error when API returns 404
    [Fact]
